#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B, C, X, Y, Z;
        scanf("%lld %lld %lld", &A, &B, &C);
        scanf("%lld %lld %lld", &X, &Y, &Z);
        long long best = 0;
        for (int i = 0; i <= 20; ++i) {
            for (int j = 0; j <= 20; ++j) {
                long long timeUsed = i * A + j * B;
                if (timeUsed > 240) continue;
                long long rem = 240 - timeUsed;
                long long k = rem / C;
                if (k > 20) k = 20;
                long long points = i * X + j * Y + k * Z;
                if (points > best) best = points;
            }
        }
        printf("%lld\n", best);
    }
    return 0;
}

