#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it))
        X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        best = 0
        for i in range(21):
            for j in range(21):
                time_used = i * A + j * B
                if time_used > 240:
                    continue
                rem = 240 - time_used
                k = rem // C
                if k > 20:
                    k = 20
                pts = i * X + j * Y + k * Z
                if pts > best:
                    best = pts
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

